package dev.harrison.rendacomcarro.finance.web;
import dev.harrison.rendacomcarro.finance.domain.*;import jakarta.validation.constraints.*;import java.math.BigDecimal;import java.time.LocalDate;import java.util.UUID;import org.springframework.format.annotation.DateTimeFormat;
public class ObligationForm {private UUID vehicleId;@NotNull private ObligationType type=ObligationType.FAMILY_LOAN;@NotNull private ObligationMode mode=ObligationMode.FLEXIBLE;@NotBlank private String creditor;@NotNull@DecimalMin("0.01")private BigDecimal principal;@DecimalMin("0")private BigDecimal annualRate=BigDecimal.ZERO;@NotNull@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)private LocalDate startDate=LocalDate.now();@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)private LocalDate firstDueDate;private Integer termMonths;private BigDecimal plannedInstallment;private BigDecimal monthlyTarget;private String notes;public UUID getVehicleId(){return vehicleId;}public void setVehicleId(UUID v){vehicleId=v;}public ObligationType getType(){return type;}public void setType(ObligationType v){type=v;}public ObligationMode getMode(){return mode;}public void setMode(ObligationMode v){mode=v;}public String getCreditor(){return creditor;}public void setCreditor(String v){creditor=v;}public BigDecimal getPrincipal(){return principal;}public void setPrincipal(BigDecimal v){principal=v;}public BigDecimal getAnnualRate(){return annualRate;}public void setAnnualRate(BigDecimal v){annualRate=v;}public LocalDate getStartDate(){return startDate;}public void setStartDate(LocalDate v){startDate=v;}public LocalDate getFirstDueDate(){return firstDueDate;}public void setFirstDueDate(LocalDate v){firstDueDate=v;}public Integer getTermMonths(){return termMonths;}public void setTermMonths(Integer v){termMonths=v;}public BigDecimal getPlannedInstallment(){return plannedInstallment;}public void setPlannedInstallment(BigDecimal v){plannedInstallment=v;}public BigDecimal getMonthlyTarget(){return monthlyTarget;}public void setMonthlyTarget(BigDecimal v){monthlyTarget=v;}public String getNotes(){return notes;}public void setNotes(String v){notes=v;}}
